package form;

import controller.SiswaController;
import java.awt.*;
import java.util.List;
import javax.swing.*;
import javax.swing.table.DefaultTableModel;
import javax.swing.table.TableRowSorter;
import model.Kelas;
import model.Siswa;
import util.UIUtils;

public class SiswaForm extends JPanel { private final SiswaController c=new SiswaController(); private final DefaultTableModel model=new DefaultTableModel(new String[]{"ID","No","NIS","Nama","Kelas","JK","Alamat"},0){ public boolean isCellEditable(int r,int c){return false;}}; private final JTable table=new JTable(model); public SiswaForm(){ setLayout(new BorderLayout()); JPanel p=UIUtils.page("Siswa"); JTextField search=UIUtils.textField(24); JButton add=UIUtils.button("TAMBAH",UIUtils.GREEN), edit=UIUtils.button("EDIT",UIUtils.BLUE), del=UIUtils.button("HAPUS",UIUtils.RED); p.add(UIUtils.toolbar(search,add,edit,del),BorderLayout.NORTH); JPanel card=UIUtils.card(); card.add(UIUtils.tableScroll(table)); p.add(card); add(p); table.removeColumn(table.getColumnModel().getColumn(0)); TableRowSorter<DefaultTableModel> sorter=new TableRowSorter<>(model); table.setRowSorter(sorter); UIUtils.bindSearch(search,sorter); add.addActionListener(e->dialog(null)); edit.addActionListener(e->{Siswa s=selected(); if(s!=null)dialog(s);}); del.addActionListener(e->{Siswa s=selected(); if(s!=null&&UIUtils.showConfirm(this,"Hapus siswa?")){c.delete(s.getId()); load();}}); load(); } private Siswa selected(){ int r=table.getSelectedRow(); if(r<0)return null; int m=table.convertRowIndexToModel(r); int id=(int)model.getValueAt(m,0); return c.getById(id); } private void load(){ model.setRowCount(0); int no=1; for(Siswa s:c.getAll())model.addRow(new Object[]{s.getId(),no++,s.getNis(),s.getNamaSiswa(),s.getNamaKelas(),s.getJenisKelamin(),s.getAlamat()}); } private void dialog(Siswa s){ JTextField nis=UIUtils.textField(16), nama=UIUtils.textField(24), alamat=UIUtils.textField(30); JComboBox<UIUtils.Option> kelas=kelasBox(); JComboBox<UIUtils.Option> jk=UIUtils.comboBox(new UIUtils.Option[]{new UIUtils.Option(0,"L"),new UIUtils.Option(0,"P")}); if(s!=null){nis.setText(s.getNis()); nama.setText(s.getNamaSiswa()); alamat.setText(s.getAlamat()); select(kelas,s.getIdKelas()); if("P".equals(s.getJenisKelamin()))jk.setSelectedIndex(1);} JPanel p=new JPanel(new GridLayout(0,1,6,6)); p.add(UIUtils.formLabel("NIS"));p.add(nis);p.add(UIUtils.formLabel("Nama Lengkap"));p.add(nama);p.add(UIUtils.formLabel("Kelas"));p.add(kelas);p.add(UIUtils.formLabel("Jenis Kelamin"));p.add(jk);p.add(UIUtils.formLabel("Alamat"));p.add(alamat); if(JOptionPane.showConfirmDialog(this,p,s==null?"Tambah Siswa":"Edit Siswa",JOptionPane.OK_CANCEL_OPTION)==JOptionPane.OK_OPTION){ if(nis.getText().trim().isEmpty()){UIUtils.showError(this,"NIS wajib diisi");return;} UIUtils.Option ko=(UIUtils.Option)kelas.getSelectedItem(); UIUtils.Option jo=(UIUtils.Option)jk.getSelectedItem(); Siswa val=new Siswa(s==null?0:s.getId(),nis.getText(),nama.getText(),ko==null?0:ko.id,"",jo==null?"L":jo.label,alamat.getText()); if(c.save(val)){UIUtils.showSuccess(this,"Data tersimpan"); load();}else UIUtils.showError(this,"Gagal menyimpan. Pastikan NIS unik."); } } private JComboBox<UIUtils.Option> kelasBox(){ List<Kelas> ks=c.getAllKelas(); UIUtils.Option[] arr=new UIUtils.Option[ks.size()]; for(int i=0;i<ks.size();i++)arr[i]=new UIUtils.Option(ks.get(i).getId(),ks.get(i).getNamaKelas()); return UIUtils.comboBox(arr); } private void select(JComboBox<UIUtils.Option> cb,int id){ for(int i=0;i<cb.getItemCount();i++) if(cb.getItemAt(i).id==id) cb.setSelectedIndex(i); } }
